# Big O Analysis Examples

# O(1) - Constant Time
def get_first(arr):
    return arr[0]  # Access by index is O(1)

# O(n) - Linear Time
def find_max(arr):
    max_val = arr[0]
    for num in arr:  # Loop through all elements
        if num > max_val:
            max_val = num
    return max_val

# O(n^2) - Quadratic Time
def bubble_sort(arr):
    n = len(arr)
    for i in range(n):  # Outer loop O(n)
        for j in range(n - i - 1):  # Inner loop O(n)
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
    return arr

# O(log n) - Logarithmic Time
def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:  # Halves search space each iteration
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

# Space Complexity Examples
# O(1) space - in place
def reverse_array(arr):
    left, right = 0, len(arr) - 1
    while left < right:
        arr[left], arr[right] = arr[right], arr[left]
        left += 1
        right -= 1
    return arr

# O(n) space - new array
def create_copy(arr):
    return arr.copy()  # Creates new array

# O(n) space - recursion
def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)  # n recursive calls on stack

# Pattern Recognition Examples
# Two Pointer Pattern - Two Sum (sorted array)
def two_sum_sorted(arr, target):
    left, right = 0, len(arr) - 1
    while left < right:
        current_sum = arr[left] + arr[right]
        if current_sum == target:
            return [left, right]
        elif current_sum < target:
            left += 1
        else:
            right -= 1
    return []

# Sliding Window Pattern - Max Sum Subarray of Size K
def max_sum_subarray(arr, k):
    max_sum = float('-inf')
    window_sum = 0
    for i in range(len(arr)):
        window_sum += arr[i]
        if i >= k:
            window_sum -= arr[i - k]
        if i >= k - 1:
            max_sum = max(max_sum, window_sum)
    return max_sum

# Binary Search Pattern
def search_rotated(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        if arr[left] <= arr[mid]:  # Left half sorted
            if arr[left] <= target < arr[mid]:
                right = mid - 1
            else:
                left = mid + 1
        else:  # Right half sorted
            if arr[mid] < target <= arr[right]:
                left = mid + 1
            else:
                right = mid - 1
    return -1

